// TestNovelWhoHelpWires smoke-tests that the who command resolves at runtime
// and renders --help without error.
func TestNovelWhoHelpWires(t *testing.T) {
	cmd := RootCmd()
	cmd.SetArgs([]string{"who", "--help"})
	cmd.SetOut(io.Discard)
	cmd.SetErr(io.Discard)
	if err := cmd.Execute(); err != nil {
		t.Fatalf("who --help error = %v (novel command not wired correctly?)", err)
	}
}

