func TestNovelWhoParseEntityRef(t *testing.T) {
	cases := []struct {
		in       string
		wantType string
		wantID   int64
		wantErr  bool
	}{
		{"opportunity:88", "opportunity", 88, false},
		{"Opportunity:5", "opportunity", 5, false},
		{"person:42", "person", 42, false},
		{"opportunity:", "", 0, true},
		{":88", "", 0, true},
		{"opportunity", "", 0, true},
		{"opportunity:abc", "", 0, true},
	}
	for _, tc := range cases {
		ref, err := parseEntityRef(tc.in)
		if tc.wantErr {
			if err == nil {
				t.Errorf("parseEntityRef(%q) = %+v, want error", tc.in, ref)
			}
			continue
		}
		if err != nil {
			t.Errorf("parseEntityRef(%q) error = %v", tc.in, err)
			continue
		}
		if ref.Type != tc.wantType || ref.ID != tc.wantID {
			t.Errorf("parseEntityRef(%q) = {%s %d}, want {%s %d}", tc.in, ref.Type, ref.ID, tc.wantType, tc.wantID)
		}
	}
}

func TestNovelWhoBehavior(t *testing.T) {
	s := newTestStore(t)
	seedOpp(t, s, "88", map[string]any{
		"name": "Big Deal", "company_id": 5, "primary_contact_id": 7,
		"status": "Open", "monetary_value": 12000.0,
	})
	seedCompany(t, s, "5", map[string]any{"name": "Acme Corp"})
	seedPerson(t, s, "7", map[string]any{"name": "Jane Buyer", "email": "jane@acme.com"})
	seedActivity(t, s, "900", map[string]any{
		"details":       "Demo call",
		"activity_date": 1750000000,
		"parent":        map[string]any{"type": "opportunity", "id": 88},
	})
	// An activity on a different opp must NOT appear.
	seedActivity(t, s, "901", map[string]any{
		"details": "Unrelated",
		"parent":  map[string]any{"type": "opportunity", "id": 99},
	})

	res, err := runWho(context.Background(), s.DB(), 88)
	if err != nil {
		t.Fatalf("runWho: %v", err)
	}
	if res == nil {
		t.Fatal("runWho returned nil for existing opp 88")
	}
	if got, _ := asInt64(res.Opportunity["id"]); got != 88 {
		t.Errorf("opportunity id = %v, want 88", res.Opportunity["id"])
	}
	if res.Company == nil {
		t.Fatal("company missing")
	}
	if got, _ := asInt64(res.Company["id"]); got != 5 {
		t.Errorf("company id = %v, want 5", res.Company["id"])
	}
	if len(res.People) != 1 {
		t.Fatalf("people = %d, want 1", len(res.People))
	}
	if got, _ := asInt64(res.People[0]["id"]); got != 7 {
		t.Errorf("person id = %v, want 7", res.People[0]["id"])
	}
	if len(res.Activities) != 1 {
		t.Fatalf("activities = %d, want 1", len(res.Activities))
	}
	if got, _ := asInt64(res.Activities[0]["id"]); got != 900 {
		t.Errorf("activity id = %v, want 900", res.Activities[0]["id"])
	}

	// Missing opp → nil result, no error.
	missing, err := runWho(context.Background(), s.DB(), 12345)
	if err != nil {
		t.Fatalf("runWho missing: %v", err)
	}
	if missing != nil {
		t.Errorf("runWho(12345) = %+v, want nil", missing)
	}
}
